from flask import Flask, session, request, jsonify
import redis

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Redis connection setup
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0)

def cache_expensive_query(func):
    def wrapper(*args, **kwargs):
        cache_key = f"cache:{func.__name__}:{args}:{kwargs}"
        result = redis_client.get(cache_key)
        if result is not None:
            return result.decode('utf-8')
        
        result = func(*args, **kwargs)
        redis_client.setex(cache_key, 3600, result)  # Cache for 1 hour
        return result
    return wrapper

@app.route('/set_session', methods=['POST'])
def set_session():
    user_id = request.json.get('user_id')
    session['user_id'] = user_id
    redis_client.set(f"session:{user_id}", json.dumps(session))
    return jsonify({'message': 'Session set successfully'})

@app.route('/get_session', methods=['GET'])
def get_session():
    user_id = session.get('user_id')
    if not user_id:
        return jsonify({'error': 'No session found'}), 404
    
    session_data = redis_client.get(f"session:{user_id}")
    if not session_data:
        return jsonify({'error': 'Session data not found'}), 404
    
    return jsonify(json.loads(session_data))

